import{c as a,Q as i,j as p,m as e}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"FFmpeg 心智模型","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/07-FFmpeg心智模型.md","filePath":"mediaTechLearning/07-FFmpeg心智模型.md","lastUpdated":1780887690000}'),t={name:"mediaTechLearning/07-FFmpeg心智模型.md"};function n(l,s,h,k,d,o){return i(),p("div",null,[...s[0]||(s[0]=[e(`<h1 id="ffmpeg-心智模型" tabindex="-1">FFmpeg 心智模型 <a class="header-anchor" href="#ffmpeg-心智模型" aria-label="Permalink to &quot;FFmpeg 心智模型&quot;">​</a></h1><p>FFmpeg 难不是命令多,是你不知道命令改的是哪一层。</p><blockquote><p>一句话先记住:<strong>FFmpeg = 解封装 -&gt; 解码 -&gt; 过滤 -&gt; 编码 -&gt; 封装 的管线工具</strong>。<code>-c copy</code> 跳过解码和编码,所以快;加滤镜必须解码再编码,所以慢。</p></blockquote><hr><h2 id="一、默认管线" tabindex="-1">一、默认管线 <a class="header-anchor" href="#一、默认管线" aria-label="Permalink to &quot;一、默认管线&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>input.mp4</span></span>
<span class="line"><span>  -&gt; demux 解封装</span></span>
<span class="line"><span>  -&gt; decode 解码</span></span>
<span class="line"><span>  -&gt; filter 滤镜</span></span>
<span class="line"><span>  -&gt; encode 编码</span></span>
<span class="line"><span>  -&gt; mux 封装</span></span>
<span class="line"><span>output.mp4</span></span></code></pre></div><p>最普通命令:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mov</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><p>FFmpeg 会按输出后缀和默认规则选择编码器、封装器。生产不要完全依赖默认值,要显式写清楚。</p><hr><h2 id="二、转封装为什么快" tabindex="-1">二、转封装为什么快 <a class="header-anchor" href="#二、转封装为什么快" aria-label="Permalink to &quot;二、转封装为什么快&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mkv</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> copy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><p>管线变成:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>demux -&gt; mux</span></span></code></pre></div><p>不解码,不编码,只是把包从一个容器挪到另一个容器。前提是目标容器支持这些流。</p><hr><h2 id="三、转码为什么慢" tabindex="-1">三、转码为什么慢 <a class="header-anchor" href="#三、转码为什么慢" aria-label="Permalink to &quot;三、转码为什么慢&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mov</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -crf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 23</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aac</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><p>管线:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>demux -&gt; decode -&gt; encode -&gt; mux</span></span></code></pre></div><p>视频编码最吃资源。1080p 还能靠 CPU,4K 大批量就要考虑硬件编码、任务队列、分片并发和成本。</p><hr><h2 id="四、滤镜一定触发重编码" tabindex="-1">四、滤镜一定触发重编码 <a class="header-anchor" href="#四、滤镜一定触发重编码" aria-label="Permalink to &quot;四、滤镜一定触发重编码&quot;">​</a></h2><p>缩放:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scale=1280:-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><p>加水印:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logo.png</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -filter_complex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;overlay=20:20&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> copy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><p>滤镜作用在解码后的原始帧上,所以视频必须重新编码。音频没动时可以 <code>-c:a copy</code>。</p><hr><h2 id="五、流选择-别让-ffmpeg-替你猜" tabindex="-1">五、流选择:别让 FFmpeg 替你猜 <a class="header-anchor" href="#五、流选择-别让-ffmpeg-替你猜" aria-label="Permalink to &quot;五、流选择:别让 FFmpeg 替你猜&quot;">​</a></h2><p>多音轨、多字幕时要用 <code>-map</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mkv</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -map</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0:v:0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -map</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0:a:0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aac</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><p>含义:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0:v:0  第 0 个输入的第 1 条视频流</span></span>
<span class="line"><span>0:a:0  第 0 个输入的第 1 条音频流</span></span></code></pre></div><p>没有 <code>-map</code>,FFmpeg 会按默认策略选流,可能不是你想要的。</p><hr><h2 id="六、先-ffprobe-再-ffmpeg" tabindex="-1">六、先 ffprobe,再 ffmpeg <a class="header-anchor" href="#六、先-ffprobe-再-ffmpeg" aria-label="Permalink to &quot;六、先 ffprobe,再 ffmpeg&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffprobe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -hide_banner</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffprobe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -show_format</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -show_streams</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span></span></code></pre></div><p>先确认:</p><ul><li>容器</li><li>视频编码</li><li>音频编码</li><li>分辨率 / 帧率</li><li>像素格式</li><li>时长 / 码率</li><li>是否多音轨 / 多字幕</li></ul><p>不要一上来就转码。很多问题只需要转封装。</p><hr><h2 id="七、踩坑提醒" tabindex="-1">七、踩坑提醒 <a class="header-anchor" href="#七、踩坑提醒" aria-label="Permalink to &quot;七、踩坑提醒&quot;">​</a></h2><ol><li><strong>不写编码器</strong>——默认值可能变,也可能不符合生产要求。</li><li><strong>该 <code>-c copy</code> 时重编码</strong>——浪费时间和画质。</li><li><strong>用了滤镜还想 copy 视频</strong>——逻辑上不可能。</li><li><strong>多流文件不用 <code>-map</code></strong>——输出丢音轨很常见。</li><li><strong>不看 stderr</strong>——FFmpeg 的关键信息都在标准错误输出。</li></ol><p>下一篇:<code>08-ffmpeg / ffprobe 常用命令.md</code>。</p>`,45)])])}const c=a(t,[["render",n]]);export{g as __pageData,c as default};
